import LocalizedStrings from 'react-localization';
import { isEmpty } from 'lodash';

class ContainerConstants {
  containerInstance = null;
  languagePreference;
  constructor() {
    // const localStorageLanguagePreference = 'en';
    // if (localStorageLanguagePreference) {
    //   this.languagePreference = localStorageLanguagePreference;

    // } else {
    //   this.languagePreference = 'en';
    // }

    const localStorageLanguagePreference = window.localStorage.getItem('FareyeLanguagePreference');
   const languagePreferenceArray = window.navigator.languages;
   if (localStorageLanguagePreference) {
     this.languagePreference = localStorageLanguagePreference;
   } else if (!isEmpty(languagePreferenceArray)) {
     this.languagePreference = languagePreferenceArray[0];
   } else {
     this.languagePreference = 'en';
   }
  }

  loadLanguage(languagePreference) {
    const localizedStringObject = {};
    const englishStringObject = require('./englishStrings').default;
    switch (languagePreference) {
      case 'en': {
        const englishStrings = require('./englishStrings');
        localizedStringObject.en = englishStrings.default;
        break;
      }
    case 'hi': {
       const hindiStrings = require('./hindiStrings');
       localizedStringObject.hi = {...englishStringObject,...hindiStrings.default};
       break;
     }
     case 'pt': {
       const portugueseStrings = require('./portugueseStrings');
       localizedStringObject.pt = {...englishStringObject,...portugueseStrings.default};
       break;
     }
     case 'es': {
       const spanishStrings = require('./spanishStrings');
       localizedStringObject.es = {...englishStringObject,...spanishStrings.default};
       break;
     }
     case 'vi': {
       const vietnameseStrings = require('./vietnameseStrings');
       localizedStringObject.vi = {...englishStringObject,...vietnameseStrings.default};
       break;
     }
     case 'ar': {
       const arabicStrings = require('./arabicStrings');
       localizedStringObject.ar = {...englishStringObject,...arabicStrings.default};
       break;
     }
     case 'ur': {
       const urduStrings = require('./urduStrings');
       localizedStringObject.ur = {...englishStringObject,...urduStrings.default};
       break;
     }
     case 'ms': {
       const malayStrings = require('./malayStrings');
       localizedStringObject.ms = {...englishStringObject,...malayStrings.default};
       break;
     }
     case 'th': {
       const thaiStrings = require('./thaiStrings');
       localizedStringObject.th = {...englishStringObject,...thaiStrings.default};
       break;
     }
     case 'bg': {
       const bulgarianStrings = require('./bulgarianStrings');
       localizedStringObject.bg = {...englishStringObject,...bulgarianStrings.default};
       break;
     }
     case 'fi': {
       const finnishStrings = require('./finnishStrings');
       localizedStringObject.fi = {...englishStringObject,...finnishStrings.default} ;
       break;
     }

     case 'da':{
       const danishStrings = require('./danishStrings');
       localizedStringObject.da = {...englishStringObject,...danishStrings.default} ;
       break;
     }
     case 'ro':{
       const romanianStrings = require('./romanianStrings');
       localizedStringObject.ro = {...englishStringObject,...romanianStrings.default} ;
       break;
     }
     case 'gu': {
       const gujaratiStrings = require('./gujaratiStrings');
       localizedStringObject.gu = {...englishStringObject,...gujaratiStrings.default} ;
       break;
     }
     case 'fr': {
       const frenchStrings = require('./frenchStrings');
       localizedStringObject.fr = {...englishStringObject,...frenchStrings.default} ;
       break;
     }
     case 'it': {
       const italianStrings = require('./italianStrings');
       localizedStringObject.it = {...englishStringObject,...italianStrings.default} ;
       break;
     }
     case 'pl': {
       const polishStrings = require('./polishStrings');
       localizedStringObject.pl = {...englishStringObject,...polishStrings.default} ;
       break;
     }
     case 'sv': {
       const swedishStrings = require('./swedishStrings');
       localizedStringObject.sv = {...englishStringObject,...swedishStrings.default} ;
       break;
     }
     case 'de': {
       const germanStrings = require('./germanStrings');
       localizedStringObject.de = {...englishStringObject,...germanStrings.default} ;
       break;
     }
     case 'lt': {
       const lithuanianStrings = require('./lithuanianStrings');
       localizedStringObject.lt = {...englishStringObject,...lithuanianStrings.default} ;
       break;
     }
     case 'el': {
       const greekStrings = require('./greekStrings');
       localizedStringObject.el = {...englishStringObject, ...greekStrings.default};
       break;
     }
      default: {
        const englishStrings = require('./englishStrings');
        localizedStringObject.en = englishStrings.default;
      }
    }
    return new LocalizedStrings(localizedStringObject);
  }

  getInstance() {
    //window.localStorage.getItem('FareyeLanguagePreference')
    const localStorageLanguagePreference = window.localStorage.getItem('FareyeLanguagePreference');
    if (localStorageLanguagePreference) {
      this.languagePreference = localStorageLanguagePreference;
    }
    if (this.containerInstance === null || this.containerInstance.getLanguage() !== this.languagePreference) {
      this.containerInstance = this.loadLanguage(this.languagePreference);
    }
    return this.containerInstance;
  }
}
export const containerConstantsService = new ContainerConstants();
